from typing import Dict, List, Optional, Tuple
from dataclasses import dataclass
from enum import Enum
import uuid

class UserTier(Enum):
    REGULAR = "regular"
    PREMIUM = "premium"
    VIP = "vip"

class DiscountCodeType(Enum):
    PUBLIC = "public"
    PREMIUM = "premium"
    VIP = "vip"
    ADMIN = "admin"

@dataclass
class CartItem:
    product_id: str
    name: str
    price: float
    quantity: int

@dataclass
class DiscountCode:
    code: str
    discount_type: DiscountCodeType
    discount_value: float
    valid_for_tiers: List[UserTier]
    is_admin_only: bool

@dataclass
class Order:
    order_id: str
    user_id: str
    items: List[CartItem]
    subtotal: float
    discount_amount: float
    tax_amount: float
    total_amount: float
    discount_code: Optional[str]
    status: str = "pending"

class CheckoutProcessor:
    def __init__(self):
        self.discount_codes = {
            "SAVE10": DiscountCode("SAVE10", DiscountCodeType.PUBLIC, 0.10, 
                                 [UserTier.REGULAR, UserTier.PREMIUM, UserTier.VIP], False),
            "SAVE20": DiscountCode("SAVE20", DiscountCodeType.PREMIUM, 0.20, 
                                 [UserTier.PREMIUM, UserTier.VIP], False),
            "SAVE30": DiscountCode("SAVE30", DiscountCodeType.VIP, 0.30, 
                                 [UserTier.VIP], False),
            "ADMIN15": DiscountCode("ADMIN15", DiscountCodeType.ADMIN, 0.15, 
                                  [UserTier.REGULAR, UserTier.PREMIUM, UserTier.VIP], True)
        }
    
    def validate_cart_items(self, cart_items: List[CartItem], user_tier: UserTier) -> Tuple[bool, str, float]:
        if not cart_items:
            return False, "Cart is empty", 0.0
            
        total = 0.0
        for item in cart_items:
            if item.quantity <= 0:
                return False, f"Invalid quantity for {item.name}", 0.0
            if item.price < 0:
                return False, f"Invalid price for {item.name}", 0.0
            total += item.price * item.quantity
            
        return True, "Cart items valid", total
    
    def apply_discount_code(self, cart_total: float, discount_code: str, 
                          user_id: str, user_tier: UserTier, 
                          is_admin: bool = False) -> Tuple[bool, str, float, Optional[DiscountCode]]:
        if not discount_code:
            return True, "No discount applied", cart_total, None
            
        if discount_code not in self.discount_codes:
            return False, "Invalid discount code", cart_total, None
            
        code = self.discount_codes[discount_code]
        
        # Check admin-only codes
        if code.is_admin_only and not is_admin:
            return False, "Admin-only discount code", cart_total, None
            
        # Check user tier eligibility
        if user_tier not in code.valid_for_tiers:
            return False, f"Discount code not available for {user_tier.value} tier", cart_total, None
            
        # Apply discount
        discount_amount = cart_total * code.discount_value
        new_total = cart_total - discount_amount
        
        return True, "Discount applied successfully", new_total, code
    
    def calculate_tax(self, amount: float, tax_rate: float = 0.08) -> Tuple[bool, str, float]:
        if amount < 0:
            return False, "Invalid amount for tax calculation", 0.0
            
        tax_amount = amount * tax_rate
        total_with_tax = amount + tax_amount
        
        return True, "Tax calculated successfully", tax_amount
    
    def process_payment(self, total_amount: float, payment_method: str, 
                       user_id: str, user_tier: UserTier) -> Tuple[bool, str, str]:
        if total_amount <= 0:
            return False, "Invalid payment amount", ""
            
        if not payment_method:
            return False, "Payment method required", ""
            
        # Simulate payment processing
        payment_id = f"PAY_{uuid.uuid4().hex[:8]}"
        return True, "Payment processed successfully", payment_id
    
    def create_order_record(self, user_id: str, items: List[CartItem], 
                          subtotal: float, discount_amount: float, 
                          tax_amount: float, total_amount: float, 
                          discount_code: Optional[str], 
                          payment_id: str) -> Order:
        order_id = f"ORD_{uuid.uuid4().hex[:10]}"
        order = Order(
            order_id=order_id,
            user_id=user_id,
            items=items,
            subtotal=subtotal,
            discount_amount=discount_amount,
            tax_amount=tax_amount,
            total_amount=total_amount,
            discount_code=discount_code,
            status="completed"
        )
        return order
    
    def process_checkout(self, user_id: str, user_tier: UserTier, 
                        cart_items: List[CartItem], discount_code: str,
                        payment_method: str, is_admin: bool = False) -> Dict:
        # Step 1: Validate cart items
        is_valid, message, cart_total = self.validate_cart_items(cart_items, user_tier)
        if not is_valid:
            return {"success": False, "error": message}
        
        # Step 2: Apply discount code
        discount_valid, discount_message, discounted_total, applied_code = self.apply_discount_code(
            cart_total, discount_code, user_id, user_tier, is_admin
        )
        if not discount_valid:
            return {"success": False, "error": discount_message}
        
        # Step 3: Calculate tax
        tax_valid, tax_message, tax_amount = self.calculate_tax(discounted_total)
        if not tax_valid:
            return {"success": False, "error": tax_message}
        
        # Step 4: Process payment
        payment_valid, payment_message, payment_id = self.process_payment(
            discounted_total + tax_amount, payment_method, user_id, user_tier
        )
        if not payment_valid:
            return {"success": False, "error": payment_message}
        
        # Step 5: Create order record
        final_total = discounted_total + tax_amount
        order = self.create_order_record(
            user_id, cart_items, cart_total, 
            cart_total - discounted_total, tax_amount, 
            final_total, discount_code if applied_code else None, 
            payment_id
        )
        
        return {
            "success": True,
            "order": order,
            "payment_id": payment_id,
            "total_amount": final_total
        }

